arguments.file_text:
@page "/"
@rendermode InteractiveServer
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<VetClinic.Data.ApplicationDbContext> DbFactory

<PageTitle>Dashboard - VetClinic</PageTitle>

<h1>🐾 Veterinary Clinic Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-3">
        <div class="card text-bg-primary mb-3">
            <div class="card-body">
                <h5 class="card-title">Patients</h5>
                <p class="card-text display-6">@petCount</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-success mb-3">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayAppointments</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-warning mb-3">
            <div class="card-body">
                <h5 class="card-title">Pending Invoices</h5>
                <p class="card-text display-6">@pendingInvoices</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-info mb-3">
            <div class="card-body">
                <h5 class="card-title">Owners</h5>
                <p class="card-text display-6">@ownerCount</p>
            </div>
        </div>
    </div>
</div>

<div class="row mt-3">
    <div class="col-md-6">
        <h4>Upcoming Appointments</h4>
        @if (upcomingAppointments.Any())
        {
            <table class="table table-striped">
                <thead><tr><th>Time</th><th>Pet</th><th>Reason</th></tr></thead>
                <tbody>
                    @foreach (var apt in upcomingAppointments)
                    {
                        <tr>
                            <td>@apt.StartTime.ToString("g")</td>
                            <td>@apt.Pet.Name</td>
                            <td>@apt.Reason</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No upcoming appointments.</p>
        }
    </div>
    <div class="col-md-6">
        <h4>Recent Treatments</h4>
        @if (recentTreatments.Any())
        {
            <table class="table table-striped">
                <thead><tr><th>Date</th><th>Pet</th><th>Title</th></tr></thead>
                <tbody>
                    @foreach (var t in recentTreatments)
                    {
                        <tr>
                            <td>@t.Date.ToString("d")</td>
                            <td>@t.Pet.Name</td>
                            <td>@t.Title</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No recent treatments.</p>
        }
    </div>
</div>

@code {
    private int petCount, ownerCount, todayAppointments, pendingInvoices;
    private List<VetClinic.Data.Models.Appointment> upcomingAppointments = [];
    private List<VetClinic.Data.Models.TreatmentNote> recentTreatments = [];

    protected override async Task OnInitializedAsync()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var today = DateTime.Today;

        petCount = await db.Pets.CountAsync();
        ownerCount = await db.Owners.CountAsync();
        todayAppointments = await db.Appointments
            .CountAsync(a => a.StartTime.Date == today && a.Status == Data.Models.AppointmentStatus.Scheduled);
        pendingInvoices = await db.Invoices
            .CountAsync(i => i.Status == Data.Models.InvoiceStatus.Pending);

        upcomingAppointments = await db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.StartTime >= DateTime.Now && a.Status == Data.Models.AppointmentStatus.Scheduled)
            .OrderBy(a => a.StartTime)
            .Take(5)
            .ToListAsync();

        recentTreatments = await db.TreatmentNotes
            .Include(t => t.Pet)
            .OrderByDescending(t => t.Date)
            .Take(5)
            .ToListAsync();
    }
}

@page "/patients"
@rendermode InteractiveServer
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

@using Microsoft.EntityFrameworkCore
@using VetClinic.Data.Models
@inject IDbContextFactory<VetClinic.Data.ApplicationDbContext> DbFactory

<PageTitle>Patients - VetClinic</PageTitle>

<h2>Patient Records</h2>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search pets or owners..." @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-primary" @onclick="ShowAddOwner">+ New Owner</button>
        <button class="btn btn-success" @onclick="ShowAddPet">+ New Pet</button>
    </div>
</div>

@if (showOwnerForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingOwner.Id == 0 ? "New Owner" : "Edit Owner")</div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-3">
                    <label class="form-label">First Name*</label>
                    <input class="form-control" @bind="editingOwner.FirstName" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Last Name*</label>
                    <input class="form-control" @bind="editingOwner.LastName" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Phone</label>
                    <input class="form-control" @bind="editingOwner.Phone" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Email</label>
                    <input class="form-control" @bind="editingOwner.Email" />
                </div>
            </div>
            <button class="btn btn-primary mt-2" @onclick="SaveOwner">Save</button>
            <button class="btn btn-secondary mt-2" @onclick="() => showOwnerForm = false">Cancel</button>
        </div>
    </div>
}

@if (showPetForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingPet.Id == 0 ? "Register New Pet" : "Edit Pet")</div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-2">
                    <label class="form-label">Name*</label>
                    <input class="form-control" @bind="editingPet.Name" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Species*</label>
                    <input class="form-control" @bind="editingPet.Species" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Breed</label>
                    <input class="form-control" @bind="editingPet.Breed" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Date of Birth</label>
                    <input type="date" class="form-control" @bind="editingPet.DateOfBirth" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Weight (kg)</label>
                    <input type="number" step="0.1" class="form-control" @bind="editingPet.WeightKg" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Owner*</label>
                    <select class="form-select" @bind="editingPet.OwnerId">
                        <option value="0">-- Select --</option>
                        @foreach (var o in owners)
                        {
                            <option value="@o.Id">@o.FullName</option>
                        }
                    </select>
                </div>
            </div>
            <button class="btn btn-success mt-2" @onclick="SavePet">Save</button>
            <button class="btn btn-secondary mt-2" @onclick="() => showPetForm = false">Cancel</button>
        </div>
    </div>
}

<table class="table table-hover">
    <thead>
        <tr><th>Pet</th><th>Species</th><th>Breed</th><th>Owner</th><th>Actions</th></tr>
    </thead>
    <tbody>
        @foreach (var pet in FilteredPets)
        {
            <tr>
                <td>@pet.Name</td>
                <td>@pet.Species</td>
                <td>@pet.Breed</td>
                <td>@pet.Owner.FullName</td>
                <td>
                    <button class="btn btn-sm btn-outline-primary" @onclick="() => ViewPet(pet)">View</button>
                    <button class="btn btn-sm btn-outline-secondary" @onclick="() => EditPet(pet)">Edit</button>
                </td>
            </tr>
        }
    </tbody>
</table>

@if (selectedPet != null)
{
    <div class="card mt-3">
        <div class="card-header d-flex justify-content-between">
            <span><strong>@selectedPet.Name</strong> — Medical History</span>
            <button class="btn btn-sm btn-primary" @onclick="ShowAddTreatment">+ Add Treatment Note</button>
        </div>
        <div class="card-body">
            <p><strong>Species:</strong> @selectedPet.Species | <strong>Breed:</strong> @selectedPet.Breed | <strong>DOB:</strong> @selectedPet.DateOfBirth?.ToString("d") | <strong>Weight:</strong> @selectedPet.WeightKg kg</p>

            @if (showTreatmentForm)
            {
