<h4>Schedule for @selectedDate.ToString("D")</h4>

<div class="row">
    <div class="col-md-8">
        <table class="table table-bordered">
            <thead><tr><th>Time</th><th>Pet</th><th>Reason</th><th>Vet</th><th>Status</th><th>Actions</th></tr></thead>
            <tbody>
                @foreach (var apt in dayAppointments)
                {
                    <tr class="@GetRowClass(apt.Status)">
                        <td>@apt.StartTime.ToString("HH:mm") - @apt.EndTime.ToString("HH:mm")</td>
                        <td>@apt.Pet.Name</td>
                        <td>@apt.Reason</td>
                        <td>@apt.Veterinarian</td>
                        <td>@apt.Status</td>
                        <td>
                            @if (apt.Status == AppointmentStatus.Scheduled)
                            {
                                <button class="btn btn-sm btn-outline-primary" @onclick="() => Reschedule(apt)">Reschedule</button>
                                <button class="btn btn-sm btn-outline-success" @onclick="() => Complete(apt)">Complete</button>
                                <button class="btn btn-sm btn-outline-danger" @onclick="() => Cancel(apt)">Cancel</button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
        @if (!dayAppointments.Any())
        {
            <p class="text-muted">No appointments for this date.</p>
        }
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-header">Available Slots</div>
            <div class="card-body">
                @foreach (var slot in availableSlots)
                {
                    <span class="badge bg-success me-1 mb-1">@slot.ToString("HH:mm")</span>
                }
                @if (!availableSlots.Any())
                {
                    <p class="text-muted">No available slots.</p>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private DateTime selectedDate = DateTime.Today;
    private DateOnly appointmentDate = DateOnly.FromDateTime(DateTime.Today);
    private TimeOnly appointmentTime = new(9, 0);
    private int durationMinutes = 30;
    private bool showForm;
    private string formError = "";
    private Appointment editingAppointment = new();
    private List<Appointment> dayAppointments = [];
    private List<Pet> pets = [];
    private List<DateTime> availableSlots = [];

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        pets = await db.Pets.Include(p => p.Owner).ToListAsync();
        dayAppointments = await db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.StartTime.Date == selectedDate.Date && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime)
            .ToListAsync();

        CalculateAvailableSlots();
    }

    private void CalculateAvailableSlots()
    {
        availableSlots.Clear();
        var start = selectedDate.Date.AddHours(8);
        var end = selectedDate.Date.AddHours(18);

        for (var time = start; time < end; time = time.AddMinutes(30))
        {
            var slotEnd = time.AddMinutes(30);
            bool conflict = dayAppointments.Any(a => a.StartTime < slotEnd && a.EndTime > time);
            if (!conflict)
                availableSlots.Add(time);
        }
    }

    private void ShowCreateForm()
    {
        editingAppointment = new();
        appointmentDate = DateOnly.FromDateTime(selectedDate);
        appointmentTime = new TimeOnly(9, 0);
        durationMinutes = 30;
        formError = "";
        showForm = true;
    }

    private void Reschedule(Appointment apt)
    {
        editingAppointment = new() { Id = apt.Id, PetId = apt.PetId, Reason = apt.Reason, Veterinarian = apt.Veterinarian, Notes = apt.Notes };
        appointmentDate = DateOnly.FromDateTime(apt.StartTime);
        appointmentTime = TimeOnly.FromDateTime(apt.StartTime);
        durationMinutes = (int)(apt.EndTime - apt.StartTime).TotalMinutes;
        formError = "";
        showForm = true;
    }

    private async Task SaveAppointment()
    {
        var startDt = appointmentDate.ToDateTime(appointmentTime);
        var endDt = startDt.AddMinutes(durationMinutes);

        using var db = await DbFactory.CreateDbContextAsync();

        // Check conflicts
        bool conflict = await db.Appointments
            .Where(a => a.Id != editingAppointment.Id && a.Status == AppointmentStatus.Scheduled)
            .AnyAsync(a => a.StartTime < endDt && a.EndTime > startDt);

        if (conflict)
        {
            formError = "Time slot conflicts with an existing appointment.";
            return;
        }

        if (editingAppointment.Id == 0)
        {
            var apt = new Appointment
            {
                PetId = editingAppointment.PetId,
                StartTime = startDt,
                EndTime = endDt,
                Reason = editingAppointment.Reason,
                Veterinarian = editingAppointment.Veterinarian,
                Notes = editingAppointment.Notes,
                Status = AppointmentStatus.Scheduled
            };
            db.Appointments.Add(apt);
        }
        else
        {
            var apt = await db.Appointments.FindAsync(editingAppointment.Id);
            if (apt != null)
            {
                apt.PetId = editingAppointment.PetId;
                apt.StartTime = startDt;
                apt.EndTime = endDt;
                apt.Reason = editingAppointment.Reason;
                apt.Veterinarian = editingAppointment.Veterinarian;
                apt.Notes = editingAppointment.Notes;
            }
        }

        await db.SaveChangesAsync();
        showForm = false;
        formError = "";
        await LoadData();
    }

    private async Task Complete(Appointment apt)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Appointments.FindAsync(apt.Id);
        if (entity != null) { entity.Status = AppointmentStatus.Completed; await db.SaveChangesAsync(); }
        await LoadData();
    }

    private async Task Cancel(Appointment apt)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Appointments.FindAsync(apt.Id);
        if (entity != null) { entity.Status = AppointmentStatus.Cancelled; await db.SaveChangesAsync(); }
        await LoadData();
    }

    private string GetRowClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Completed => "table-success",
        AppointmentStatus.Cancelled => "table-secondary",
        _ => ""
    };
}

