@code {
    private int petCount, ownerCount, todayAppointments, pendingInvoices;
    private List<VetClinic.Data.Models.Appointment> upcomingAppointments = [];
    private List<VetClinic.Data.Models.TreatmentNote> recentTreatments = [];

    protected override async Task OnInitializedAsync()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var today = DateTime.Today;

        petCount = await db.Pets.CountAsync();
        ownerCount = await db.Owners.CountAsync();
        todayAppointments = await db.Appointments
            .CountAsync(a => a.StartTime.Date == today && a.Status == Data.Models.AppointmentStatus.Scheduled);
        pendingInvoices = await db.Invoices
            .CountAsync(i => i.Status == Data.Models.InvoiceStatus.Pending);

        upcomingAppointments = await db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.StartTime >= DateTime.Now && a.Status == Data.Models.AppointmentStatus.Scheduled)
            .OrderBy(a => a.StartTime)
            .Take(5)
            .ToListAsync();

        recentTreatments = await db.TreatmentNotes
            .Include(t => t.Pet)
            .OrderByDescending(t => t.Date)
            .Take(5)
            .ToListAsync();
    }
}

