{"file_text": "@page "/billing"
@rendermode InteractiveServer
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

@using Microsoft.EntityFrameworkCore
@using VetClinic.Data.Models
@inject IDbContextFactory<VetClinic.Data.ApplicationDbContext> DbFactory

<PageTitle>Billing - VetClinic</PageTitle>

<h2>Billing & Payments</h2>

<ul class="nav nav-tabs mb-3">
    <li class="nav-item">
        <button class="nav-link @(activeTab == "invoices" ? "active" : "")" @onclick='() => activeTab = "invoices"'>Invoices</button>
    </li>
    <li class="nav-item">
        <button class="nav-link @(activeTab == "payments" ? "active" : "")" @onclick='() => activeTab = "payments"'>Payment History</button>
    </li>
</ul>

@if (activeTab == "invoices")
{
    <div class="mb-3">
        <button class="btn btn-primary" @onclick="ShowCreateInvoice">+ New Invoice</button>
    </div>

    @if (showInvoiceForm)
    {
        <div class="card mb-3">
            <div class="card-header">New Invoice</div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-3">
                        <label class="form-label">Owner*</label>
                        <select class="form-select" @bind="newInvoice.OwnerId">
                            <option value="0">-- Select --</option>
                            @foreach (var o in owners)
                            {
                                <option value="@o.Id">@o.FullName</option>
                            }
                        </select>
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Pet</label>
                        <select class="form-select" @bind="newInvoice.PetId">
                            <option value="">-- Optional --</option>
                            @foreach (var p in pets.Where(p => p.OwnerId == newInvoice.OwnerId))
                            {
                                <option value="@p.Id">@p.Name</option>
                            }
                        </select>
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Amount*</label>
                        <input type="number" step="0.01" class="form-control" @bind="newInvoice.Amount" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Due Date</label>
                        <input type="date" class="form-control" @bind="newInvoice.DueDate" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Description</label>
                        <input class="form-control" @bind="newInvoice.Description" />
                    </div>
                </div>
                <button class="btn btn-primary mt-2" @onclick="SaveInvoice">Create Invoice</button>
                <button class="btn btn-secondary mt-2" @onclick="() => showInvoiceForm = false">Cancel</button>
            </div>
        </div>
    }

    <table class="table table-hover">
        <thead>
            <tr><th>#</th><th>Date</th><th>Owner</th><th>Pet</th><th>Amount</th><th>Paid</th><th>Status</th><th>Actions</th></tr>
        </thead>
        <tbody>
            @foreach (var inv in invoices)
            {
                <tr class="@GetInvoiceRowClass(inv.Status)">
                    <td>@inv.Id</td>
                    <td>@inv.IssuedDate.ToString("d")</td>
                    <td>@inv.Owner.FullName</td>
                    <td>@inv.Pet?.Name</td>
                    <td>@inv.Amount.ToString("C")</td>
                    <td>@inv.TotalPaid.ToString("C")</td>
                    <td><span class="badge @GetBadgeClass(inv.Status)">@inv.Status</span></td>
                    <td>
                        @if (inv.Status != InvoiceStatus.Paid)
                        {
                            <button class="btn btn-sm btn-outline-success" @onclick="() => ShowPayment(inv)">Record Payment</button>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>

    @if (showPaymentForm)
    {
        <div class="card mb-3">
            <div class="card-header">Record Payment for Invoice #@payingInvoice!.Id (Balance: @payingInvoice!.Balance.ToString("C"))</div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-3">
                        <label class="form-label">Amount*</label>
                        <input type="number" step="0.01" class="form-control" @bind="newPayment.Amount" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Method</label>
                        <select class="form-select" @bind="newPayment.Method">
                            @foreach (var m in Enum.GetValues<PaymentMethod>())
                            {
                                <option value="@m">@m</option>
                            }
                        </select>
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Reference</label>
                        <input class="form-control" @bind="newPayment.Reference" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Date</label>
                        <input type="date" class="form-control" @bind="newPayment.Date" />
                    </div>
                </div>
                <button class="btn btn-success mt-2" @onclick="ProcessPayment">Process Payment</button>
                <button class="btn btn-secondary mt-2" @onclick="() => showPaymentForm = false">Cancel</button>
            </div>
        </div>
    }
}
else
{
    <h4>Payment History</h4>
    <table class="table table-striped">
        <thead>
            <tr><th>Date</th><th>Invoice #</th><th>Owner</th><th>Amount</th><th>Method</th><th>Reference</th></tr>
        </thead>
        <tbody>
            @foreach (var pmt in allPayments)
            {
                <tr>
                    <td>@pmt.Date.ToString("d")</td>
                    <td>@pmt.InvoiceId</td>
                    <td>@pmt.Invoice.Owner.FullName</td>
                    <td>@pmt.Amount.ToString("C")</td>
                    <td>@pmt.Method</td>
                    <td>@pmt.Reference</td>
                </tr>
            }
        </tbody>
    </table>
    @if (!allPayments.Any())
    {
        <p class="text-muted">No payments recorded yet.</p>
    }
}

@code {
    private string activeTab = "invoices";
    private bool showInvoiceForm, showPaymentForm;
    private Invoice newInvoice = new();
    private Payment newPayment = new();
    private Invoice? payingInvoice;
    private List<Invoice> invoices = [];
    private List<Payment> allPayments = [];
    private List<Owner> owners = [];
    private List<Pet> pets = [];

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        invoices = await db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.Pet)
            .Include(i => i.Payments)
            .OrderByDescending(i => i.IssuedDate)
            .ToListAsync();
        allPayments = await db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Owner)
            .OrderByDescending(p => p.Date)
            .ToListAsync();
        owners = await db.Owners.ToListAsync();
        pets = await db.Pets.ToListAsync();
    }

    private void ShowCreateInvoice()
    {
        newInvoice = new() { IssuedDate = DateTime.Now, DueDate = DateTime.Now.AddDays(30) };
        showInvoiceForm = true;
    }

    private async Task SaveInvoice()
    {
        if (newInvoice.OwnerId == 0 || newInvoice.Amount <= 0) return;
        using var db = await DbFactory.CreateDbContextAsync();
        db.Invoices.Add(newInvoice);
        await db.SaveChangesAsync();
        showInvoiceForm = false;
        await LoadData();
    }

    private void ShowPayment(Invoice inv)
    {
        payingInvoice = inv;
        newPayment = new() { InvoiceId = inv.Id, Amount = inv.Balance, Date = DateTime.Now };
        showPaymentForm = true;
    }

    private async Task ProcessPayment()
    {
        if (newPayment.Amount <= 0) return;
        using var db = await DbFactory.CreateDbContextAsync();
        db.Payments.Add(newPayment);

        var invoice = await db.Invoices.Include(i => i.Payments).FirstAsync(i => i.Id == newPayment.InvoiceId);
        var totalPaid = invoice.Payments.Sum(p => p.Amount) + newPayment.Amount;
        if (totalPaid >= invoice.Amount)
            invoice.Status = InvoiceStatus.Paid;

        await db.SaveChangesAsync();
        showPaymentForm = false;
        await LoadData();
    }

    private string GetInvoiceRowClass(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Paid => "table-success",
        InvoiceStatus.Overdue => "table-danger",
        _ => ""
    };

    private string GetBadgeClass(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Overdue => "bg-danger",
        _ => "bg-warning text-dark"
    };
}
