    {
        using var db = await DbFactory.CreateDbContextAsync();
        if (editingOwner.Id == 0)
            db.Owners.Add(editingOwner);
        else
            db.Owners.Update(editingOwner);
        await db.SaveChangesAsync();
        showOwnerForm = false;
        await LoadData();
    }

    private async Task SavePet()
    {
        if (editingPet.OwnerId == 0) return;
        using var db = await DbFactory.CreateDbContextAsync();
        if (editingPet.Id == 0)
            db.Pets.Add(editingPet);
        else
            db.Pets.Update(editingPet);
        await db.SaveChangesAsync();
        showPetForm = false;
        await LoadData();
    }

    private async Task SaveTreatment()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        db.TreatmentNotes.Add(editingTreatment);
        await db.SaveChangesAsync();
        showTreatmentForm = false;
        await LoadData();
        selectedPet = pets.FirstOrDefault(p => p.Id == selectedPet?.Id);
    }
}

